const btnModal=document.querySelector("._modalBtn"),modalWindow=document.querySelector("._modalWindow"),modalClose=document.querySelector("._closeModal");btnModal.addEventListener("click",function(){modalWindow.classList.add("modal__open")}),modalClose.addEventListener("click",function(){modalWindow.classList.remove("modal__open")}),document.querySelector(".modal__mask").addEventListener("click",function(){modalWindow.classList.remove("modal__open")}),document.querySelector(".modal__mask--body").addEventListener("click",function(o){o.stopPropagation()});